<?php
namespace App\Http\Controllers\Api\V1;
use App\Http\Controllers\Controller; use App\Http\Requests\StoreMessageRequest; use App\Http\Resources\MessageResource; use App\Models\Circle; use App\Models\Footprint; use App\Models\Message; use Illuminate\Http\Resources\Json\AnonymousResourceCollection;
class MessageController extends Controller { public function index(Circle $circle): AnonymousResourceCollection { abort_unless($circle->members()->whereKey(request()->user()->id)->exists(),403); $messages=$circle->messages()->with('sender')->latest('id')->paginate(50); return MessageResource::collection($messages); } public function store(StoreMessageRequest $request, Circle $circle): MessageResource { abort_unless($circle->members()->whereKey($request->user()->id)->exists(),403); $days=$circle->retentionPolicy?->message_retention_days ?? config('footprints.default_retention_days'); $message=Message::create(['circle_id'=>$circle->id,'sender_user_id'=>$request->user()->id,'body'=>$request->body,'retention_until'=>now()->addDays($days)]); $circle->touch(); Footprint::record('message.created',$request->user(),$circle,['message_id'=>$message->id]); return new MessageResource($message->load('sender')); } }
